import numpy as np

def bi_encoder_cosine(u, v):
    return np.dot(u, v) / (np.linalg.norm(u) * np.linalg.norm(v))

def run_practice():
    u = np.array([1.0, 0.0])
    v = np.array([1.0, 0.0])
    assert np.allclose(bi_encoder_cosine(u, v), 1.0)
    print('[PASS] Bi-encoder check passed.')

if __name__ == '__main__':
    run_practice()
